INSERT INTO `rewrite_record` VALUES (1,3,'TEXT','chinese',NULL,'AI移除_260112_1 (降AI能力一般，改写幅度小，学术性强，非一逗到底）','针对甘蔗病虫害传统人工巡查效率低下且早期防控困难的问题，本文设计了一套基于YOLOv8的智能识别系统。利用Roboflow平台构建了包含斜纹夜蛾、蝼蛄、黄叶病等六类病害虫的图像数据集，共计7392张。经比较，YOLOv8s模型凭借94.2%的mAP@0.5等优越性能被选作基准模型。采用“小轮验证—大轮训练—问题反馈—小轮再验证—大轮确认”的迭代流程，结合mosaic、cutmix等数据增强策略及正则化调节，有效抑制了过拟合现象。最终模型在测试集上的mAP@0.5达到91.6%，精确率和召回率分别为89.3%和91.2%。系统依托Streamlit框架构建，集成了单张图像、批量图像、视频流及实时摄像头四种检测方式，并内嵌知识库以实现防治建议的自动推送。实验结果表明，该系统兼具较高的准确率与实时响应能力，为甘蔗病虫害的智能化防控提供了可行的技术路径','针对甘蔗病虫害传统人工巡查效率低、早期防控难的问题，本文设计出一个基于YOLOv8的智能识别系统。使用Roboflow平台创建了以斜纹夜蛾、蝼蛄、黄叶病这三种病害虫为对象的图像数据集，共有7392张。经比较，YOLOv8s模型凭借94.2%的mAP@0.5等优越性能被选作基准模型。采用小轮验证、大轮训练、问题反馈、小轮再验证、大轮确认的迭代过程，用mosaic、cutmix等数据增强策略和正则化调节来抑制过拟合现象。最终模型在测试集上的mAP@0.5达到91.6%，精确率和召回率分别为89.3%和91.2%。系统使用Streamlit框架来建立，有单张图像、批量图像、视频流和实时摄像头这四种检测方式，而且内置了知识库，可以对防治建议进行自动推送。从实验结果可知，该系统具有较高的准确率和实时响应速度，为甘蔗病虫害智能化防控提供了一条可行的技术途径',NULL,NULL,NULL,NULL,270,0.4050,'{\"cost\": 0.1188, \"success\": true, \"request_id\": \"50ac1c02-aa82-4048-b80a-419aa819378f\", \"preset_name\": \"AI移除_260112_1 (降AI能力一般，改写幅度小，学术性强，非一逗到底）\", \"preset_used\": \"aigcmove_tp_s_1\", \"original_text\": \"针对甘蔗病虫害传统人工巡查效率低下且早期防控困难的问题，本文设计了一套基于YOLOv8的智能识别系统。利用Roboflow平台构建了包含斜纹夜蛾、蝼蛄、黄叶病等六类病害虫的图像数据集，共计7392张。经比较，YOLOv8s模型凭借94.2%的mAP@0.5等优越性能被选作基准模型。采用“小轮验证—大轮训练—问题反馈—小轮再验证—大轮确认”的迭代流程，结合mosaic、cutmix等数据增强策略及正则化调节，有效抑制了过拟合现象。最终模型在测试集上的mAP@0.5达到91.6%，精确率和召回率分别为89.3%和91.2%。系统依托Streamlit框架构建，集成了单张图像、批量图像、视频流及实时摄像头四种检测方式，并内嵌知识库以实现防治建议的自动推送。实验结果表明，该系统兼具较高的准确率与实时响应能力，为甘蔗病虫害的智能化防控提供了可行的技术路径\", \"processing_time\": 9.52, \"characters_count\": 270, \"paraphrased_text\": \"针对甘蔗病虫害传统人工巡查效率低、早期防控难的问题，本文设计出一个基于YOLOv8的智能识别系统。使用Roboflow平台创建了以斜纹夜蛾、蝼蛄、黄叶病这三种病害虫为对象的图像数据集，共有7392张。经比较，YOLOv8s模型凭借94.2%的mAP@0.5等优越性能被选作基准模型。采用小轮验证、大轮训练、问题反馈、小轮再验证、大轮确认的迭代过程，用mosaic、cutmix等数据增强策略和正则化调节来抑制过拟合现象。最终模型在测试集上的mAP@0.5达到91.6%，精确率和召回率分别为89.3%和91.2%。系统使用Streamlit框架来建立，有单张图像、批量图像、视频流和实时摄像头这四种检测方式，而且内置了知识库，可以对防治建议进行自动推送。从实验结果可知，该系统具有较高的准确率和实时响应速度，为甘蔗病虫害智能化防控提供了一条可行的技术途径\", \"language_detected\": \"chinese\", \"remaining_balance\": 487.785}',50.0000,49.5950,'2026-05-14 22:23:52'),(2,3,'TEXT','chinese',NULL,'AI移除_260112_1 (降AI能力一般，改写幅度小，学术性强，非一逗到底）','甘蔗作为世界上最重要的糖料作物和能源作物之一，在我国南方农业经济中占据着举足轻重的地位。随着全球食糖需求的持续增长以及生物燃料产业的兴起，提高甘蔗的产量与质量已成为保障国家食糖安全和能源战略的关键。然而在实际种植过程中，甘蔗的生长极易受到气候环境、土壤肥力以及各种生物灾害的侵扰。特别是病虫害的频繁发生，往往导致甘蔗出现枯萎、产量下降甚至绝收的现象，这不仅直接损害了广大农户的经济利益，也对整个制糖产业链的稳定性造成了巨大的威胁。\n在传统的农业生产模式下，甘蔗病虫害的排查主要依赖于人工巡检。这种方式要求技术人员具备极高的专业背景和长期的实战经验，能够通过肉眼识别叶片、茎秆上的细微病变特征。但在大规模种植基地中，人工巡检不仅耗时耗力，而且容易受到主观因素的影响，导致漏诊或误诊。由于甘蔗生长周期长、植株高大且种植密度极高，田间环境异常复杂，往往在病虫害暴发初期难以被及时察觉，一旦形成规模，防控难度和治理成本将呈几何倍数增加，研发一种能够快速、精准识别病虫害的智能化手段显得尤为迫切','甘蔗是世界上最重要的糖料作物和能源作物之一，在我国南方的农业经济中占有着举足轻重的地位。随着全球食糖需求不断上升、生物燃料产业不断发展，提高甘蔗产量和质量已经成了保证国家食糖安全、能源战略的重要问题。但是甘蔗的生长很容易受到气候环境、土壤肥力、各种生物灾害等的影响。特别是病虫害频繁发生的时候，甘蔗就会出现枯萎、产量下降甚至绝收的情况，这既直接给广大农户带来了经济上的损失，又给整个制糖产业链的稳定运行带来了极大的隐患。\n传统的农业生产模式中，甘蔗病虫害的排查主要是依靠人工巡查。这种方式需要有较高的专业知识水平和实战经验，主要是通过对叶片、茎秆上的细微病变特征进行观察来完成的。但是大面积的种植基地上人工巡检既费时费力，又容易受到主观因素的干扰而出现漏诊、误诊的情况。由于甘蔗生长周期长、植株高大、种植密度过高，田间环境比较复杂，在病虫害暴发初期很难发现，一旦形成规模，防控难度和治理成本就会呈几何倍数增加，因此开发出一种能够快速、准确检测病虫害的方法变得尤为重要',NULL,NULL,NULL,NULL,413,0.6195,'{\"cost\": 0.1817, \"success\": true, \"request_id\": \"7002d583-f728-428d-881f-8c9128393e1a\", \"preset_name\": \"AI移除_260112_1 (降AI能力一般，改写幅度小，学术性强，非一逗到底）\", \"preset_used\": \"aigcmove_tp_s_1\", \"original_text\": \"甘蔗作为世界上最重要的糖料作物和能源作物之一，在我国南方农业经济中占据着举足轻重的地位。随着全球食糖需求的持续增长以及生物燃料产业的兴起，提高甘蔗的产量与质量已成为保障国家食糖安全和能源战略的关键。然而在实际种植过程中，甘蔗的生长极易受到气候环境、土壤肥力以及各种生物灾害的侵扰。特别是病虫害的频繁发生，往往导致甘蔗出现枯萎、产量下降甚至绝收的现象，这不仅直接损害了广大农户的经济利益，也对整个制糖产业链的稳定性造成了巨大的威胁。\\n在传统的农业生产模式下，甘蔗病虫害的排查主要依赖于人工巡检。这种方式要求技术人员具备极高的专业背景和长期的实战经验，能够通过肉眼识别叶片、茎秆上的细微病变特征。但在大规模种植基地中，人工巡检不仅耗时耗力，而且容易受到主观因素的影响，导致漏诊或误诊。由于甘蔗生长周期长、植株高大且种植密度极高，田间环境异常复杂，往往在病虫害暴发初期难以被及时察觉，一旦形成规模，防控难度和治理成本将呈几何倍数增加，研发一种能够快速、精准识别病虫害的智能化手段显得尤为迫切\", \"processing_time\": 2.27, \"characters_count\": 413, \"paraphrased_text\": \"甘蔗是世界上最重要的糖料作物和能源作物之一，在我国南方的农业经济中占有着举足轻重的地位。随着全球食糖需求不断上升、生物燃料产业不断发展，提高甘蔗产量和质量已经成了保证国家食糖安全、能源战略的重要问题。但是甘蔗的生长很容易受到气候环境、土壤肥力、各种生物灾害等的影响。特别是病虫害频繁发生的时候，甘蔗就会出现枯萎、产量下降甚至绝收的情况，这既直接给广大农户带来了经济上的损失，又给整个制糖产业链的稳定运行带来了极大的隐患。\\n传统的农业生产模式中，甘蔗病虫害的排查主要是依靠人工巡查。这种方式需要有较高的专业知识水平和实战经验，主要是通过对叶片、茎秆上的细微病变特征进行观察来完成的。但是大面积的种植基地上人工巡检既费时费力，又容易受到主观因素的干扰而出现漏诊、误诊的情况。由于甘蔗生长周期长、植株高大、种植密度过高，田间环境比较复杂，在病虫害暴发初期很难发现，一旦形成规模，防控难度和治理成本就会呈几何倍数增加，因此开发出一种能够快速、准确检测病虫害的方法变得尤为重要\", \"language_detected\": \"chinese\", \"remaining_balance\": 487.6033}',49.5950,48.9755,'2026-05-14 22:24:38'),(3,3,'TEXT','chinese',NULL,'AI移除_260112_1 (降AI能力一般，改写幅度小，学术性强，非一逗到底）','开发基于计算机视觉的甘蔗病虫害检测系统，能够将繁重的人工观测转化为高效的机器识别。这种技术手段的应用可以显著提升病虫害检测的频率和覆盖范围，实现对蔗田健康状况的实时掌握。通过在发病初期精准定位发病位置并识别特定种类，农户能够采取针对性的局部施药措施，避免了以往因无法定性而导致的大面积盲目用药。这不仅降低了农药采购成本，更重要的是减轻了化学药剂对土壤和水源的污染，对推动绿色农业和可持续发展具有深远的实践意义。\n从技术落地的角度来看，本研究通过集成先进的深度学习算法与防治知识库，打破了农业技术信息不对称的瓶颈。系统在输出检测结果的基础上，能够及时关联相应的农业防治建议，使缺乏专业植保知识的基层农户也能在第一时间内获得科学的指导方案。这种“检测即处理”的模式极大地缩短了从发现灾情到采取行动的时间差，提升了田间管理的科学化水平。同时，相关技术的成熟也将为其他农作物的智能化生产提供参考范式，助力智慧农业从实验室研究走向真正的田间应用','创建计算机视觉的甘蔗病虫害检测系统，可以把繁重的人工观察变成高效的机器识别。使用这些技术手段后，可以大大提高病虫害检测的频率和范围，从而达到对蔗田健康状况进行及时掌握的目的。在发病初期准确找到发病部位和种类，农户可以有针对性地进行局部施药，避免了以前由于不能定性而造成的大面积盲目用药。既降低了农药的采购成本，又减轻了化学药剂对土壤、水源的污染，对推进绿色农业、可持续发展有重要的实践意义。\n就技术应用来说，本文用先进的深度学习算法和防治知识库来打破农业技术信息不平等的壁垒。系统在输出检测结果之后，可以马上联系相关的农业防治建议，使没有专业植保知识的基层农户也可以在第一时间得到科学的指导方案。检测就是处理，检测与处理相融合的方式大大缩短了发现灾情到采取措施的时间间隔，提高了田间管理的科学性。相关技术成熟之后就会给其他作物智能生产提供范式，使智慧农业从实验室研究走向真正的田间应用',NULL,NULL,NULL,NULL,394,0.5910,'{\"cost\": 0.1734, \"success\": true, \"request_id\": \"9d48254c-286a-449a-82c1-63df53557a5b\", \"preset_name\": \"AI移除_260112_1 (降AI能力一般，改写幅度小，学术性强，非一逗到底）\", \"preset_used\": \"aigcmove_tp_s_1\", \"original_text\": \"开发基于计算机视觉的甘蔗病虫害检测系统，能够将繁重的人工观测转化为高效的机器识别。这种技术手段的应用可以显著提升病虫害检测的频率和覆盖范围，实现对蔗田健康状况的实时掌握。通过在发病初期精准定位发病位置并识别特定种类，农户能够采取针对性的局部施药措施，避免了以往因无法定性而导致的大面积盲目用药。这不仅降低了农药采购成本，更重要的是减轻了化学药剂对土壤和水源的污染，对推动绿色农业和可持续发展具有深远的实践意义。\\n从技术落地的角度来看，本研究通过集成先进的深度学习算法与防治知识库，打破了农业技术信息不对称的瓶颈。系统在输出检测结果的基础上，能够及时关联相应的农业防治建议，使缺乏专业植保知识的基层农户也能在第一时间内获得科学的指导方案。这种“检测即处理”的模式极大地缩短了从发现灾情到采取行动的时间差，提升了田间管理的科学化水平。同时，相关技术的成熟也将为其他农作物的智能化生产提供参考范式，助力智慧农业从实验室研究走向真正的田间应用\", \"processing_time\": 1.49, \"characters_count\": 394, \"paraphrased_text\": \"创建计算机视觉的甘蔗病虫害检测系统，可以把繁重的人工观察变成高效的机器识别。使用这些技术手段后，可以大大提高病虫害检测的频率和范围，从而达到对蔗田健康状况进行及时掌握的目的。在发病初期准确找到发病部位和种类，农户可以有针对性地进行局部施药，避免了以前由于不能定性而造成的大面积盲目用药。既降低了农药的采购成本，又减轻了化学药剂对土壤、水源的污染，对推进绿色农业、可持续发展有重要的实践意义。\\n就技术应用来说，本文用先进的深度学习算法和防治知识库来打破农业技术信息不平等的壁垒。系统在输出检测结果之后，可以马上联系相关的农业防治建议，使没有专业植保知识的基层农户也可以在第一时间得到科学的指导方案。检测就是处理，检测与处理相融合的方式大大缩短了发现灾情到采取措施的时间间隔，提高了田间管理的科学性。相关技术成熟之后就会给其他作物智能生产提供范式，使智慧农业从实验室研究走向真正的田间应用\", \"language_detected\": \"chinese\", \"remaining_balance\": 487.4299}',48.9755,48.3845,'2026-05-14 22:24:58'),(4,2,'TEXT','chinese',NULL,'AI移除_260112_1 (降AI能力一般，改写幅度小，学术性强，非一逗到底）','初代的YOLO架构奠定了全卷积网络的基础，随后在不断的版本迭代中，研究人 \n员引入了锚框机制、多尺度特征融合以及更科学的特征提取骨干网络，使得算法在 处理不同尺寸目标，尤其是小尺寸目标时的漏检率显著下降，逐步成为工业界和学术界应用最广泛的检测框架之一。 \n进入深度学习成熟期后，YOLO系列算法的演进方向开始向工业级精度与速度的 \n极致平衡靠拢。从追求复杂网络结构的堆叠，转向关注训练策略、样本匹配方案以 及网络结构的轻量化重构。后续的版本开始舍弃性能开销巨大的操作，引入了如解耦检测头、无锚框机制以及更高效的损失函数。这一系列改进不仅提升了模型对重 叠目标的区分能力，还降低了对显存资源的需求。YOLOv6作为该系列中专为工业应 用设计的代表作，充分吸收了前序版本的优点，通过重参数化技术进一步挖掘了硬 件算力的潜力。','初代YOLO架构奠定了全卷积网络的基础，之后经过不断的版本迭代，研究人\n将锚框结构加入进去，并使用多尺度特征融合的方式，以及更加科学的特征提取骨干网络，使算法在处理各种尺寸的目标，特别是小目标的时候漏检率大幅降低，逐渐成为工业界及学术界使用最广泛的检测框架。\n进入深度学习成熟期之后，YOLO系列算法的发展趋向就转变为工业级精度和速度\n极致平衡靠拢。由以往注重复杂网络结构的堆叠，转变为重视训练策略、样本匹配方案和网络结构的轻量化重构。后续版本开始抛弃性能开销巨大的操作，使用解耦检测头、无锚框机制和更加高效的损失函数。该系列改进一方面可以提高模型对于重叠目标的区分度，另一方面也可以减少显存占用。YOLOv6是该系列中专门针对工业应用设计的代表性作品，它很好地继承了前几代版本的优点，并且依靠重参数化的方法来发挥出硬件算力的最大潜力。',NULL,NULL,NULL,NULL,315,0.4725,'{\"cost\": 0.1386, \"success\": true, \"request_id\": \"ff66861e-06fb-4fb2-ba1e-0081201d4f73\", \"preset_name\": \"AI移除_260112_1 (降AI能力一般，改写幅度小，学术性强，非一逗到底）\", \"preset_used\": \"aigcmove_tp_s_1\", \"original_text\": \"初代的YOLO架构奠定了全卷积网络的基础，随后在不断的版本迭代中，研究人 \\n员引入了锚框机制、多尺度特征融合以及更科学的特征提取骨干网络，使得算法在 处理不同尺寸目标，尤其是小尺寸目标时的漏检率显著下降，逐步成为工业界和学术界应用最广泛的检测框架之一。 \\n进入深度学习成熟期后，YOLO系列算法的演进方向开始向工业级精度与速度的 \\n极致平衡靠拢。从追求复杂网络结构的堆叠，转向关注训练策略、样本匹配方案以 及网络结构的轻量化重构。后续的版本开始舍弃性能开销巨大的操作，引入了如解耦检测头、无锚框机制以及更高效的损失函数。这一系列改进不仅提升了模型对重 叠目标的区分能力，还降低了对显存资源的需求。YOLOv6作为该系列中专为工业应 用设计的代表作，充分吸收了前序版本的优点，通过重参数化技术进一步挖掘了硬 件算力的潜力。\", \"processing_time\": 2.73, \"characters_count\": 315, \"paraphrased_text\": \"初代YOLO架构奠定了全卷积网络的基础，之后经过不断的版本迭代，研究人\\n将锚框结构加入进去，并使用多尺度特征融合的方式，以及更加科学的特征提取骨干网络，使算法在处理各种尺寸的目标，特别是小目标的时候漏检率大幅降低，逐渐成为工业界及学术界使用最广泛的检测框架。\\n进入深度学习成熟期之后，YOLO系列算法的发展趋向就转变为工业级精度和速度\\n极致平衡靠拢。由以往注重复杂网络结构的堆叠，转变为重视训练策略、样本匹配方案和网络结构的轻量化重构。后续版本开始抛弃性能开销巨大的操作，使用解耦检测头、无锚框机制和更加高效的损失函数。该系列改进一方面可以提高模型对于重叠目标的区分度，另一方面也可以减少显存占用。YOLOv6是该系列中专门针对工业应用设计的代表性作品，它很好地继承了前几代版本的优点，并且依靠重参数化的方法来发挥出硬件算力的最大潜力。\", \"language_detected\": \"chinese\", \"remaining_balance\": 487.2913}',50.0000,49.5275,'2026-05-14 22:25:07'),(5,3,'TEXT','chinese',NULL,'AI移除_260112_2 (降AI能力一般，改写幅度小，学术性强，非一逗到底）','国外在精准农业领域的研究起步较早，尤其是在欧美及南美的一些大规模甘蔗产区，自动化监测技术已经得到了初步应用。研究者们利用无人机搭载传感器，在大尺度范围内对甘蔗植株的生长态势进行评估。这类研究侧重于宏观的灾情预警，能够为大型农场提供决策支持。在微观的图像检测领域，Kumar等[13]对早期的深度学习方法进行了比较研究，发现在识别甘蔗早期病害方面具有显著潜力。国外实验室利用深度残差网络和特征融合技术，在提高模型泛化的稳健性方面取得了进展，Sun等[14]提出了一种名为EF-YOLOv8s的人机协作模型，显著增强了复杂环境下甘蔗病害检测的准确性。\n在系统集成与智能化服务方面，国外一些研究机构致力于构建多源数据的综合评估框架。Khan等[15]提出的SugarcaneNet2024，集成七种LASSO正则化预训练模型的加权平均，在甘蔗叶片病害分类上取得了99.67%的准确率，展示了集成学习在甘蔗病害识别中的巨大潜力。Li等[16]研发的ADQ-YOLOv8m模型，利用精确检测技术实现了对复杂环境下甘蔗病害的精细化识别。通过这种方式，系统不仅能告诉用户现状，还能结合环境数据预测趋势。此外，针对甘蔗品种优化了深度学习模型的分类效果，使系统在不同品种甘蔗间的表型差异处理上更具优势。虽然这些技术具有很高的前瞻性，但昂贵的硬件配置限制了其在广大发展中国家小农经济环境下的推广。Shoaib等[17]指出，当前最先进的深度学习模型在植物病害分类任务中准确率常超过95%，检测和分割网络的精确率超过90%，并强调将模型部署到边缘设备和农业机器人是未来的重要发展方向。\n在通用作物检测层面，Wang等[18]将CBAM引入番茄病害检测模型的特征提取网络，在PlantDoc公开数据集上的mAP相比YOLOv8提升了2.6个百分点，进一步印证了CBAM在增强病灶特征提取、抑制环境干扰方面的通用能力','国外对于精准农业的研究开始的比较早，在欧美以及南美一些大范围的甘蔗产区，已经开始了自动化监测技术的应用。研究者们用无人机装有传感器，对甘蔗植株的大规模生长状况展开评价。此类研究重视宏观上的灾情预估，可给予大型农场决策支撑。Kumar等[13]对早期的深度学习方法做了比较研究，发现甘蔗早期病害的识别有潜力。国外实验室用深度残差网络以及特征融合技术，提高了模型在复杂环境下对于甘蔗病害检测的准确度，Sun等[14]提出EF-YOLOv8s人机协作模型，在复杂的环境里大幅度提高了甘蔗病害检测的精度。\n国外一些研究机构试图创建出综合评价多源数据的体系。Khan等人提出的SugarcaneNet2024将七种LASSO正则化预训练模型的加权平均融合在一起，在甘蔗叶片病害分类上达到了99.67%的准确率，很好地证明了集成学习对于甘蔗病害识别有着巨大的优势。Li等[16]开发出ADQ-YOLOv8m模型，用精确检测的方式完成了在复杂环境下的甘蔗病害精确识别。该系统不仅可以告诉用户目前的情况，而且可以利用环境数据来预测未来的发展趋向。另外，用深度学习模型改进甘蔗品种时，也能取得更理想的效果，使系统对于品种间表型差异的处理更充分。虽然这些技术有着较高的前瞻性，但是昂贵的硬件配置使得它不能在广大发展中国家的小农经济环境下推广。Shoaib等人[17]认为目前最先进的深度学习模型对于植物病害分类任务的准确率可以达到95%以上，在检测、分割网络的精确率也大于90%，并且认为把模型部署到边缘设备、农业机器人上将会成为未来的发展方向。\n在通用作物检测方面，王等[18]把CBAM加入到番茄病害检测模型的特征提取网络当中，在PlantDoc公开数据集上mAP比YOLOv8提高了2.6个百分点，再次证明了CBAM对于病灶特征提取的增强作用以及环境干扰抑制的能力',NULL,NULL,NULL,NULL,625,0.9375,'{\"cost\": 0.275, \"success\": true, \"request_id\": \"a73365c2-1fb8-4c08-bcfc-5e692358c37c\", \"preset_name\": \"AI移除_260112_2 (降AI能力一般，改写幅度小，学术性强，非一逗到底）\", \"preset_used\": \"aigcmove_tp_s_2\", \"original_text\": \"国外在精准农业领域的研究起步较早，尤其是在欧美及南美的一些大规模甘蔗产区，自动化监测技术已经得到了初步应用。研究者们利用无人机搭载传感器，在大尺度范围内对甘蔗植株的生长态势进行评估。这类研究侧重于宏观的灾情预警，能够为大型农场提供决策支持。在微观的图像检测领域，Kumar等[13]对早期的深度学习方法进行了比较研究，发现在识别甘蔗早期病害方面具有显著潜力。国外实验室利用深度残差网络和特征融合技术，在提高模型泛化的稳健性方面取得了进展，Sun等[14]提出了一种名为EF-YOLOv8s的人机协作模型，显著增强了复杂环境下甘蔗病害检测的准确性。\\n在系统集成与智能化服务方面，国外一些研究机构致力于构建多源数据的综合评估框架。Khan等[15]提出的SugarcaneNet2024，集成七种LASSO正则化预训练模型的加权平均，在甘蔗叶片病害分类上取得了99.67%的准确率，展示了集成学习在甘蔗病害识别中的巨大潜力。Li等[16]研发的ADQ-YOLOv8m模型，利用精确检测技术实现了对复杂环境下甘蔗病害的精细化识别。通过这种方式，系统不仅能告诉用户现状，还能结合环境数据预测趋势。此外，针对甘蔗品种优化了深度学习模型的分类效果，使系统在不同品种甘蔗间的表型差异处理上更具优势。虽然这些技术具有很高的前瞻性，但昂贵的硬件配置限制了其在广大发展中国家小农经济环境下的推广。Shoaib等[17]指出，当前最先进的深度学习模型在植物病害分类任务中准确率常超过95%，检测和分割网络的精确率超过90%，并强调将模型部署到边缘设备和农业机器人是未来的重要发展方向。\\n在通用作物检测层面，Wang等[18]将CBAM引入番茄病害检测模型的特征提取网络，在PlantDoc公开数据集上的mAP相比YOLOv8提升了2.6个百分点，进一步印证了CBAM在增强病灶特征提取、抑制环境干扰方面的通用能力\", \"processing_time\": 1.9, \"characters_count\": 625, \"paraphrased_text\": \"国外对于精准农业的研究开始的比较早，在欧美以及南美一些大范围的甘蔗产区，已经开始了自动化监测技术的应用。研究者们用无人机装有传感器，对甘蔗植株的大规模生长状况展开评价。此类研究重视宏观上的灾情预估，可给予大型农场决策支撑。Kumar等[13]对早期的深度学习方法做了比较研究，发现甘蔗早期病害的识别有潜力。国外实验室用深度残差网络以及特征融合技术，提高了模型在复杂环境下对于甘蔗病害检测的准确度，Sun等[14]提出EF-YOLOv8s人机协作模型，在复杂的环境里大幅度提高了甘蔗病害检测的精度。\\n国外一些研究机构试图创建出综合评价多源数据的体系。Khan等人提出的SugarcaneNet2024将七种LASSO正则化预训练模型的加权平均融合在一起，在甘蔗叶片病害分类上达到了99.67%的准确率，很好地证明了集成学习对于甘蔗病害识别有着巨大的优势。Li等[16]开发出ADQ-YOLOv8m模型，用精确检测的方式完成了在复杂环境下的甘蔗病害精确识别。该系统不仅可以告诉用户目前的情况，而且可以利用环境数据来预测未来的发展趋向。另外，用深度学习模型改进甘蔗品种时，也能取得更理想的效果，使系统对于品种间表型差异的处理更充分。虽然这些技术有着较高的前瞻性，但是昂贵的硬件配置使得它不能在广大发展中国家的小农经济环境下推广。Shoaib等人[17]认为目前最先进的深度学习模型对于植物病害分类任务的准确率可以达到95%以上，在检测、分割网络的精确率也大于90%，并且认为把模型部署到边缘设备、农业机器人上将会成为未来的发展方向。\\n在通用作物检测方面，王等[18]把CBAM加入到番茄病害检测模型的特征提取网络当中，在PlantDoc公开数据集上mAP比YOLOv8提高了2.6个百分点，再次证明了CBAM对于病灶特征提取的增强作用以及环境干扰抑制的能力\", \"language_detected\": \"chinese\", \"remaining_balance\": 487.0163}',48.3845,47.4470,'2026-05-14 22:26:10'),(6,3,'TEXT','chinese',NULL,'AI移除_260112_3 (降AI能力强，改写幅度中，学术性中，非一逗到底）','本文聚焦于甘蔗病虫害智能检测的实际需求，旨在设计并实现一套基于YOLOv8算法的检测识别系统，涵盖数据集构建、模型选型与训练优化和可视化系统开发四个主要环节。全文共分为五个章节。\n第一章绪论：阐述甘蔗病虫害防治的研究背景与意义，分析深度学习在农作物病虫害检测领域的研究进展，针对现有方法在甘蔗场景中的应用，明确本文研究方向与技术路径。\n第二章相关技术与算法基础：阐述深度卷积神经网络原理，重点解析YOLOv8算法及优势，并介绍系统开发框架和技术，为系统实现奠定理论基础。\n第三章系统总体设计：首先介绍系统功能，确定系统支持单图、批量图像、视频及实时摄像头四种检测模式，并内嵌防治知识库。然后介绍系统整体架构，最后说明算法设计、数据集构成及评估指标。\n第四章模型设计：阐述模型的总体设计，并具体介绍各个步骤，阐述数据预处理流程、对比试验、迭代训练策略和模型调用和检测。\n第五章实验结果与分析：说明实验环境配置，展示数据标注与增强效果。通过YOLOv8n与YOLOv8s对比，选定YOLOv8s为基准模型。分析模型收敛曲线及评估结果。最后演示单图、批量、视频及实时检测功能，验证系统实用性与实时性','本文以甘蔗病虫害智能检测的实际应用为基础，对利用YOLOv8算法进行检测识别的系统设计、实现以及数据分析方法等方面的研究工作做了相关的探究。本文全文分为五章。\n第一章绪论，介绍甘蔗病虫害防治研究背景和意义，论述深度学习在农作物病虫害检测方面的发展状况，对已有方法在甘蔗上应用提出不足之处，并确定本文的研究方向和技术路线。\n第二章有关的技术和算法基础主要是讲解深度卷积神经网络的基本原理，主要分析了YOLOv8算法以及其优点，并且介绍了系统开发框架及关键技术，为系统的实现打下了理论基础。\n第三章系统总体设计首先介绍系统的功能，确定系统支持单图、批量图像、视频、实时摄像头这4种检测方式，里面带有防治知识库。接着给出系统的整体架构，然后说明算法的设计思想以及数据集的构成以及评价指标。\n第四章模型设计，描述模型的总体结构以及各个方面的设计思路，说明数据预处理的过程、对比试验的方案、迭代训练的方法、模型调用及检测等环节。\n第五章实验结果与分析：说明实验环境配置，展示数据标注与增强效果。通过YOLOv8n与YOLOv8s对比，选定YOLOv8s为基准模型。分析收敛曲线，得出分析结果。最后对测试系统的主要功能模块（图、批量、视频、实时检测等）进行测试，看看使用的是否方便，有没有滞后等问题',NULL,NULL,NULL,NULL,419,0.6285,'{\"cost\": 0.1844, \"success\": true, \"request_id\": \"1bb90843-d70e-438d-aec6-f8c949f88cbd\", \"preset_name\": \"AI移除_260112_3 (降AI能力强，改写幅度中，学术性中，非一逗到底）\", \"preset_used\": \"aigcmove_tp_s_3\", \"original_text\": \"本文聚焦于甘蔗病虫害智能检测的实际需求，旨在设计并实现一套基于YOLOv8算法的检测识别系统，涵盖数据集构建、模型选型与训练优化和可视化系统开发四个主要环节。全文共分为五个章节。\\n第一章绪论：阐述甘蔗病虫害防治的研究背景与意义，分析深度学习在农作物病虫害检测领域的研究进展，针对现有方法在甘蔗场景中的应用，明确本文研究方向与技术路径。\\n第二章相关技术与算法基础：阐述深度卷积神经网络原理，重点解析YOLOv8算法及优势，并介绍系统开发框架和技术，为系统实现奠定理论基础。\\n第三章系统总体设计：首先介绍系统功能，确定系统支持单图、批量图像、视频及实时摄像头四种检测模式，并内嵌防治知识库。然后介绍系统整体架构，最后说明算法设计、数据集构成及评估指标。\\n第四章模型设计：阐述模型的总体设计，并具体介绍各个步骤，阐述数据预处理流程、对比试验、迭代训练策略和模型调用和检测。\\n第五章实验结果与分析：说明实验环境配置，展示数据标注与增强效果。通过YOLOv8n与YOLOv8s对比，选定YOLOv8s为基准模型。分析模型收敛曲线及评估结果。最后演示单图、批量、视频及实时检测功能，验证系统实用性与实时性\", \"processing_time\": 13.89, \"characters_count\": 419, \"paraphrased_text\": \"本文以甘蔗病虫害智能检测的实际应用为基础，对利用YOLOv8算法进行检测识别的系统设计、实现以及数据分析方法等方面的研究工作做了相关的探究。本文全文分为五章。\\n第一章绪论，介绍甘蔗病虫害防治研究背景和意义，论述深度学习在农作物病虫害检测方面的发展状况，对已有方法在甘蔗上应用提出不足之处，并确定本文的研究方向和技术路线。\\n第二章有关的技术和算法基础主要是讲解深度卷积神经网络的基本原理，主要分析了YOLOv8算法以及其优点，并且介绍了系统开发框架及关键技术，为系统的实现打下了理论基础。\\n第三章系统总体设计首先介绍系统的功能，确定系统支持单图、批量图像、视频、实时摄像头这4种检测方式，里面带有防治知识库。接着给出系统的整体架构，然后说明算法的设计思想以及数据集的构成以及评价指标。\\n第四章模型设计，描述模型的总体结构以及各个方面的设计思路，说明数据预处理的过程、对比试验的方案、迭代训练的方法、模型调用及检测等环节。\\n第五章实验结果与分析：说明实验环境配置，展示数据标注与增强效果。通过YOLOv8n与YOLOv8s对比，选定YOLOv8s为基准模型。分析收敛曲线，得出分析结果。最后对测试系统的主要功能模块（图、批量、视频、实时检测等）进行测试，看看使用的是否方便，有没有滞后等问题\", \"language_detected\": \"chinese\", \"remaining_balance\": 486.8319}',47.4470,46.8185,'2026-05-14 22:26:46'),(7,2,'DOCUMENT','chinese',NULL,'AI移除_260112_1 (降AI能力一般，改写幅度小，学术性强，非一逗到底）',NULL,NULL,'https://ycjgzdywxzsboss.oss-cn-hangzhou.aliyuncs.com/document_rewrite/origin/2026/05/14/37c1f595_original_2392955733_rewrite-13812809587549792909-%E5%88%9D%E4%BB%A3%E7%9A%84YOLO%E6%9E%B6%E6%9E%84%E5%A5%A0%E5%AE%9A%E4%BA%86%E5%85%A8%E5%8D%B7%E7%A7%AF%E7%BD%91%E7%BB%9C%E7%9A%84%E5%9F%BA%E7%A1%80.docx','https://ycjgzdywxzsboss.oss-cn-hangzhou.aliyuncs.com/document_rewrite/rewritten/2026/05/14/a0ab69a5_rewritten_2392955733_rewrite-13812809587549792909-%E5%88%9D%E4%BB%A3%E7%9A%84YOLO%E6%9E%B6%E6%9E%84%E5%A5%A0%E5%AE%9A%E4%BA%86%E5%85%A8%E5%8D%B7%E7%A7%AF%E7%BD%91%E7%BB%9C%E7%9A%84%E5%9F%BA%E7%A1%80.docx','rewrite-13812809587549792909-初代的YOLO架构奠定了全卷积网络的基础.docx','a0ab69a5_rewritten_2392955733_rewrite-13812809587549792909-初代的YOLO架构奠定了全卷积网络的基础.docx',1036,1.5540,'{\"file_id\": \"ec2f26a7-eb69-4152-ada4-ac0afb295a1b\", \"success\": true, \"diff_url\": null, \"reduction\": 85.99, \"request_id\": \"ec2f26a7-eb69-4152-ada4-ac0afb295a1b\", \"actual_cost\": 0.4149, \"preset_used\": \"aigcmove_tp_s_2|5.09en\", \"original_url\": \"https://ycjgzdywxzsboss.oss-cn-hangzhou.aliyuncs.com/document_rewrite/origin/2026/05/14/37c1f595_original_2392955733_rewrite-13812809587549792909-%E5%88%9D%E4%BB%A3%E7%9A%84YOLO%E6%9E%B6%E6%9E%84%E5%A5%A0%E5%AE%9A%E4%BA%86%E5%85%A8%E5%8D%B7%E7%A7%AF%E7%BD%91%E7%BB%9C%E7%9A%84%E5%9F%BA%E7%A1%80.docx\", \"estimated_cost\": 0.4149, \"paraphrased_url\": \"https://ycjgzdywxzsboss.oss-cn-hangzhou.aliyuncs.com/document_rewrite/rewritten/2026/05/14/a0ab69a5_rewritten_2392955733_rewrite-13812809587549792909-%E5%88%9D%E4%BB%A3%E7%9A%84YOLO%E6%9E%B6%E6%9E%84%E5%A5%A0%E5%AE%9A%E4%BA%86%E5%85%A8%E5%8D%B7%E7%A7%AF%E7%BD%91%E7%BB%9C%E7%9A%84%E5%9F%BA%E7%A1%80.docx\", \"processing_time\": 6.92, \"original_ai_rate\": 92.24, \"original_filename\": \"rewrite-13812809587549792909-初代的YOLO架构奠定了全卷积网络的基础.docx\", \"remaining_balance\": 486.417, \"rewritten_ai_rate\": 6.25, \"ai_detection_success\": true}',49.5275,47.9735,'2026-05-14 22:27:10'),(8,3,'TEXT','chinese',NULL,'降重模式0325-1','OpenCV在本系统中承担了图像解码、视频读写、摄像头采集、色彩空间转换四项核心职责，贯穿于图像检测、批量检测、视频检测和摄像头检测四种模式。\n图像解码与格式转换:用户上传图片后，OpenCV将文件字节流在内存中直接解码为深度学习模型可接受的多维数组格式，无需写入磁盘再读取，减少了I/O开销。\n视频文件的读取与写入:在视频检测模式中，OpenCV负责打开视频文件并获取帧数、帧率等元信息，通过循环逐帧读取视频内容供模型推理；同时将每帧标注后的图像按原始帧率和尺寸写入新的视频文件，生成带有检测结果的视频。\n摄像头实时采集:在摄像头检测模式中，OpenCV通过设备编号打开摄像头获取实时视频流，在循环中持续读取每一帧供模型逐帧推理，检测结束后释放摄像头资源','该系统依托OpenCV库实现图像解析、视频文件读写、摄像头实时采集以及颜色空间转换等关键功能，其应用场景覆盖图像分析、批量处理、视频监控及设备调试四大模块。\n图像解析与编码转换：在用户提交图片时，OpenCV能够通过内存缓冲区直接将文件数据流转化为适配深度学习框架的多维数组形式，这一过程免去了传统IO操作中的磁盘交互步骤，从而显著提升了效率。\n视频处理功能包含读取与写入操作，在开放视觉检测场景中，OpenCV用于加载目标视频文件，并提取帧总数及帧率等基础参数信息。其后通过迭代机制逐帧解析视频数据以供模型进行推理分析，最终依据原始分辨率与帧速率标准输出标注后的图像序列至新视频文件，从而实现含检测标识的目标视频生成。\n在摄像头实时采集功能中，OpenCV借助设备索引启动摄像头并获取动态视频流。随后，基于循环机制连续捕获各帧图像，为深度学习模型提供逐帧分析与处理服务。任务完成后及时关闭摄像头连接以释放系统资源。',NULL,NULL,NULL,NULL,275,0.4125,'{\"cost\": 0.1375, \"success\": true, \"request_id\": \"7ae69da7-ec7c-4f69-ba0f-ebf029f2946c\", \"preset_name\": \"降重模式0325-1\", \"preset_used\": \"zh_jc_1_0325\", \"original_text\": \"OpenCV在本系统中承担了图像解码、视频读写、摄像头采集、色彩空间转换四项核心职责，贯穿于图像检测、批量检测、视频检测和摄像头检测四种模式。\\n图像解码与格式转换:用户上传图片后，OpenCV将文件字节流在内存中直接解码为深度学习模型可接受的多维数组格式，无需写入磁盘再读取，减少了I/O开销。\\n视频文件的读取与写入:在视频检测模式中，OpenCV负责打开视频文件并获取帧数、帧率等元信息，通过循环逐帧读取视频内容供模型推理；同时将每帧标注后的图像按原始帧率和尺寸写入新的视频文件，生成带有检测结果的视频。\\n摄像头实时采集:在摄像头检测模式中，OpenCV通过设备编号打开摄像头获取实时视频流，在循环中持续读取每一帧供模型逐帧推理，检测结束后释放摄像头资源\", \"processing_time\": 0.72, \"characters_count\": 275, \"paraphrased_text\": \"该系统依托OpenCV库实现图像解析、视频文件读写、摄像头实时采集以及颜色空间转换等关键功能，其应用场景覆盖图像分析、批量处理、视频监控及设备调试四大模块。\\n图像解析与编码转换：在用户提交图片时，OpenCV能够通过内存缓冲区直接将文件数据流转化为适配深度学习框架的多维数组形式，这一过程免去了传统IO操作中的磁盘交互步骤，从而显著提升了效率。\\n视频处理功能包含读取与写入操作，在开放视觉检测场景中，OpenCV用于加载目标视频文件，并提取帧总数及帧率等基础参数信息。其后通过迭代机制逐帧解析视频数据以供模型进行推理分析，最终依据原始分辨率与帧速率标准输出标注后的图像序列至新视频文件，从而实现含检测标识的目标视频生成。\\n在摄像头实时采集功能中，OpenCV借助设备索引启动摄像头并获取动态视频流。随后，基于循环机制连续捕获各帧图像，为深度学习模型提供逐帧分析与处理服务。任务完成后及时关闭摄像头连接以释放系统资源。\", \"language_detected\": \"chinese\", \"remaining_balance\": 486.2795}',46.8185,46.4060,'2026-05-14 22:36:57'),(9,3,'TEXT','chinese',NULL,'降重模式0325-2','OpenCV在本系统中承担了图像解码、视频读写、摄像头采集、色彩空间转换四项核心职责，贯穿于图像检测、批量检测、视频检测和摄像头检测四种模式。\n图像解码与格式转换:用户上传图片后，OpenCV将文件字节流在内存中直接解码为深度学习模型可接受的多维数组格式，无需写入磁盘再读取，减少了I/O开销。\n视频文件的读取与写入:在视频检测模式中，OpenCV负责打开视频文件并获取帧数、帧率等元信息，通过循环逐帧读取视频内容供模型推理；同时将每帧标注后的图像按原始帧率和尺寸写入新的视频文件，生成带有检测结果的视频。\n摄像头实时采集:在摄像头检测模式中，OpenCV通过设备编号打开摄像头获取实时视频流，在循环中持续读取每一帧供模型逐帧推理，检测结束后释放摄像头资源','该系统以OpenCV为技术基础，集成图像处理、视频流解析、摄像头驱动及颜色空间转换等功能模块，在图像识别、批量处理、实时监控以及硬件校准四大主要应用领域中展现出显著的应用价值与核心支撑能力。\n图像处理与编码转换：当用户上传图片时，OpenCV可利用内存缓冲机制直接完成文件解码，并将数据结构化为适应深度学习模型的多维张量形式，进而有效避免传统磁盘I/O操作，显著降低数据传输延迟。\n视频分析模块主要依托OpenCV库实现对目标视频文件的加载、解析与预处理操作。其核心功能包括：提取视频的关键属性（如帧数和帧率），并通过循环迭代逐帧捕获图像数据以满足模型输入需求；按照预设的帧率与分辨率参数，整合带有标记信息的图像序列，生成融合检测结果的新输出视频流。该流程确保了从原始视频中高效获取并呈现所需信息的能力。\n在基于摄像头的实时监控应用场景中，OpenCV通过设备索引参数构建视频捕获类实例。其关键操作表现为持续读取连续帧图像，并将每幅图像送入目标识别模型完成逐帧解析；为提高系统效能并优化内存使用效率，应在任务结束后及时调用资源回收机制。',NULL,NULL,NULL,NULL,275,0.4125,'{\"cost\": 0.1375, \"success\": true, \"request_id\": \"942d20c9-2b36-4f92-af84-a69eb7c8cbf9\", \"preset_name\": \"降重模式0325-2\", \"preset_used\": \"zh_jc_2_0325\", \"original_text\": \"OpenCV在本系统中承担了图像解码、视频读写、摄像头采集、色彩空间转换四项核心职责，贯穿于图像检测、批量检测、视频检测和摄像头检测四种模式。\\n图像解码与格式转换:用户上传图片后，OpenCV将文件字节流在内存中直接解码为深度学习模型可接受的多维数组格式，无需写入磁盘再读取，减少了I/O开销。\\n视频文件的读取与